    <!-- ORBITS -->
    <!-- The orbit circles use fixed px sizes/radii, so they'd break at
         arbitrary widths. This layer scales the whole system proportionally
         with the viewport and hides it entirely on mobile. -->
    <div
      class="orbit-layer hidden lg:block"
      aria-hidden="true"
      :style="{ transform: `scale(${orbitScale})` }"
    >
    <div
      v-for="(orbit, orbitIndex) in orbits"
      :key="orbitIndex"
      class="orbit absolute top-1/2 left-1/2 rounded-full border border-[#E7E9EE] z-10"
      :style="{
        width: orbit.size + 'px',
        height: orbit.size + 'px',
        marginLeft: -(orbit.size / 2) + 'px',
        marginTop: -(orbit.size / 2) + 'px',
        animationDuration: orbit.duration + 's',
        animationDirection: orbit.direction,
      }"
    >
      <!-- AVATARS -->
      <div
        v-for="(avatar, avatarIndex) in orbit.avatars"
        :key="avatarIndex"
        class="absolute left-1/2 top-1/2"
        :style="{
          transform: `
            translate(-50%, -50%)
            rotate(${avatar.angle}deg)
            translateX(${orbit.radius}px)
          `,
        }"
      >
        <!-- Counter rotation -->
        <div
          class="avatar"
          :style="{
            animationDuration: orbit.duration + 's',
            animationDirection:
              orbit.direction === 'normal' ? 'reverse' : 'normal',
          }"
        >
          <div
